// RISC-V 内核二进制入口。这个很小的汇编桩建立私有启动栈，
// 然后把固件传入的 hart id 和设备树指针交给 Rust。
#[cfg(target_arch = "riscv64")]
core::arch::global_asm!(
    r#"
    .section .text.entry, "ax"
    .globl _start
_start:
    la sp, __riscv64_boot_stack_top
    call riscv64_rust_entry
1:
    wfi
    j 1b

    .section .bss.stack, "aw", @nobits
    .align 12
    .globl __riscv64_boot_stack
__riscv64_boot_stack:
	    .space 2097152
    .globl __riscv64_boot_stack_top
__riscv64_boot_stack_top:
"#
);

// riscv64_rust_entry 是 内核核心代码 的辅助函数，负责 riscv64 rust entry 相关的状态更新或结果计算。
#[no_mangle]
pub extern "C" fn riscv64_rust_entry(hart_id: usize, device_tree: usize) -> ! {
    // 将固件提供的启动参数转换为架构中立的 BSP 服务，供共享内核启动路径使用。
    let boot = uestc_kernel_source::arch::riscv64::boot::early_boot_info(hart_id, device_tree);
    let bsp = uestc_kernel_source::arch::riscv64::boot::bsp_services(boot);

    uestc_kernel_source::kernel::boot::kernel_start(bsp)
}

#![no_std]
#![no_main]
#![deny(warnings)]

#[cfg(target_arch = "loongarch64")]
core::arch::global_asm!(
    r#"
    .section .text.entry, "ax"
    .globl _start
_start:
    la.local $sp, __loongarch64_boot_stack_top
    bl loongarch64_rust_entry
1:
    idle 0
    b 1b

    .section .bss.stack, "aw", @nobits
    .align 12
    .globl __loongarch64_boot_stack
__loongarch64_boot_stack:
    .space 2097152
    .globl __loongarch64_boot_stack_top
__loongarch64_boot_stack_top:
"#
);

// loongarch64_rust_entry 是 内核核心代码 的辅助函数，负责 loongarch64 rust entry 相关的状态更新或结果计算。
