//! Shared kernel pseudorandom byte source.

use core::sync::atomic::{AtomicU64, Ordering};

// PSEUDORANDOM_STATE 保存跨调用共享的状态，访问时必须保持初始化顺序和并发语义清晰。
static PSEUDORANDOM_STATE: AtomicU64 = AtomicU64::new(0x9e37_79b9_7f4a_7c15);

// 用轻量伪随机序列填充缓冲区，满足不依赖硬件随机源的内核路径。
pub fn fill_pseudorandom(diversifier: u64, out: &mut [u8]) {
    let increment = (out.len() as u64)
        .wrapping_add(1)
        .wrapping_add(diversifier.rotate_left(17));
    let mut state = PSEUDORANDOM_STATE.fetch_add(increment, Ordering::AcqRel) ^ diversifier;
    let mut index = 0usize;
    while index < out.len() {
        state ^= state << 7;
        state ^= state >> 9;
        state = state.wrapping_mul(0xa24b_aed4_963e_e407);
        out[index] = (state >> 24) as u8;
        index += 1;
    }
}

